import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"欢迎来到 Yumina 创作者指南","description":"","frontmatter":{},"headers":[],"relativePath":"creator-guide/00-welcome.md","filePath":"creator-guide/00-welcome.md","lastUpdated":null}'),o={name:"creator-guide/00-welcome.md"};function h(n,t,l,i,s,m){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="欢迎来到-yumina-创作者指南" tabindex="-1">欢迎来到 Yumina 创作者指南 <a class="header-anchor" href="#欢迎来到-yumina-创作者指南" aria-label="Permalink to &quot;欢迎来到 Yumina 创作者指南&quot;">​</a></h1><p>嗨，既然你打开了这份文档，说明你已经不满足于只当玩家了——你想自己做一个世界出来 (๑•̀ㅂ•́)و✧</p><p>这份指南会教你怎么用 Yumina 的编辑器，从一个空白世界开始，一步步搭出你脑海中的互动体验。不管你想做恋爱模拟、恐怖生存、还是硬核大逃杀，看完这份文档你都能搞定。</p><h2 id="这份文档怎么读" tabindex="-1">这份文档怎么读 <a class="header-anchor" href="#这份文档怎么读" aria-label="Permalink to &quot;这份文档怎么读&quot;">​</a></h2><p>文档分成三块，根据你的情况选一个起点就行：</p><p><strong>第一次做世界？</strong> 从 <a href="./01-beginner-guide.html">新手指南</a> 开始看。会带你认识编辑器的每个角落，搞清楚各个功能是干嘛的。看完之后跟着 <a href="./02-tutorial-basic.html">手把手教程</a> 做一个完整的世界出来，做完你就出师了 ∠( ᐛ 」∠)＿</p><p><strong>已经上手了，想查具体功能？</strong> 直接翻 <a href="#功能参考">功能参考</a> 部分。每章都分了两层——简单版帮你快速回忆，详细版把所有细节和边界情况讲透。不知道某个概念是什么？先看 <a href="./01-core-concepts.html">核心概念速览</a>。</p><p><strong>遇到问题了？</strong> 去 <a href="./13-faq.html">常见问题</a> 看看有没有你的情况，或者查 <a href="./12-glossary.html">术语表</a> 搞清楚某个词是什么意思。</p><hr><h2 id="功能参考" tabindex="-1">功能参考 <a class="header-anchor" href="#功能参考" aria-label="Permalink to &quot;功能参考&quot;">​</a></h2><table tabindex="0"><thead><tr><th>章节</th><th>一句话说明</th></tr></thead><tbody><tr><td><a href="./03-entries-and-lorebook.html">词条与世界书</a></td><td>给 AI 喂设定的地方</td></tr><tr><td><a href="./04-variables.html">变量系统</a></td><td>追踪血量、金币、好感度这些会变的东西</td></tr><tr><td><a href="./05-directives-and-macros.html">AI 指令与宏</a></td><td>AI 怎么改变游戏状态</td></tr><tr><td><a href="./06-rules-engine.html">行为规则引擎</a></td><td>自动化逻辑，不用写代码的事件系统</td></tr><tr><td><a href="./07-components.html">自定义前端指南</a></td><td>用 AI 生成游戏界面（血条、背包、视觉小说等）</td></tr><tr><td><a href="./08-message-renderer.html">自定义消息渲染器</a></td><td>彻底改造聊天消息的外观</td></tr><tr><td><a href="./09-audio.html">音频系统</a></td><td>BGM、音效、环境音</td></tr><tr><td><a href="./10-ai-settings.html">AI 模型与设置</a></td><td>调 AI 的参数</td></tr><tr><td><a href="./11-publish-and-share.html">发布、导出与 Bundle</a></td><td>做完了怎么发出去</td></tr></tbody></table><p>好了，废话不多说。翻到下一页，我们开始 ᕕ( ᐛ )ᕗ</p>',12)])])}const f=a(o,[["render",h]]);export{p as __pageData,f as default};
